import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Network Types","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/network-types.md","filePath":"theory/networks/network-types.md"}'),i={name:"theory/networks/network-types.md"};function n(s,e,l,d,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="network-types" tabindex="-1">Network Types <a class="header-anchor" href="#network-types" aria-label="Permalink to &quot;Network Types&quot;">​</a></h1><p>Not all networks are the same size. The network in your bedroom connecting your phone to your laptop is nothing like the network connecting offices across continents. Networks are classified by their geographic scope, ownership, and purpose.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>Network types (PAN, LAN, WAN) are introduced at Grade 10. Grade 11 adds MAN, HAN, and more detailed comparisons.</p></div><hr><h2 id="overview-network-classification-by-size" tabindex="-1">Overview: Network Classification by Size <a class="header-anchor" href="#overview-network-classification-by-size" aria-label="Permalink to &quot;Overview: Network Classification by Size&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Network Type</th><th>Full Name</th><th>Typical Range</th><th>Who uses it</th></tr></thead><tbody><tr><td><strong>PAN</strong></td><td>Personal Area Network</td><td>&lt; 10 metres</td><td>Individual (Bluetooth devices)</td></tr><tr><td><strong>HAN</strong></td><td>Home Area Network</td><td>Single home</td><td>Household (smart home devices)</td></tr><tr><td><strong>LAN</strong></td><td>Local Area Network</td><td>Single building/campus</td><td>School, office, home</td></tr><tr><td><strong>MAN</strong></td><td>Metropolitan Area Network</td><td>City / town</td><td>ISP, municipality, large organisation</td></tr><tr><td><strong>WAN</strong></td><td>Wide Area Network</td><td>Countries / worldwide</td><td>Businesses, internet</td></tr></tbody></table><hr><h2 id="pan-—-personal-area-network" tabindex="-1">PAN — Personal Area Network <a class="header-anchor" href="#pan-—-personal-area-network" aria-label="Permalink to &quot;PAN — Personal Area Network&quot;">​</a></h2><p>A <strong>PAN</strong> connects devices for personal use, typically within a few metres of a single person.</p><p><strong>Characteristics:</strong></p><ul><li>Range: up to 10 metres</li><li>Technologies: Bluetooth, USB, infrared (IrDA), NFC</li><li>Low speed, low power</li><li>No infrastructure required</li></ul><p><strong>Examples:</strong></p><ul><li>Wireless earphones connected to a phone</li><li>Smartwatch syncing to a smartphone</li><li>Laptop connected to a wireless mouse and keyboard</li><li>Transferring files between two phones via Bluetooth</li></ul><hr><h2 id="han-—-home-area-network" tabindex="-1">HAN — Home Area Network <a class="header-anchor" href="#han-—-home-area-network" aria-label="Permalink to &quot;HAN — Home Area Network&quot;">​</a></h2><p>A <strong>HAN</strong> connects devices within a home, often managed by a home router.</p><p><strong>Characteristics:</strong></p><ul><li>Range: single dwelling</li><li>Technologies: Wi-Fi, Ethernet, Powerline networking</li><li>Managed by consumer-grade router</li><li>Often includes smart home devices (IoT)</li></ul><p><strong>Examples:</strong></p><ul><li>Home Wi-Fi network connecting phones, TVs, and laptops</li><li>Smart home hub controlling lights, thermostat, and security cameras</li><li>Gaming consoles connected to the internet via home router</li></ul><hr><h2 id="lan-—-local-area-network" tabindex="-1">LAN — Local Area Network <a class="header-anchor" href="#lan-—-local-area-network" aria-label="Permalink to &quot;LAN — Local Area Network&quot;">​</a></h2><p>A <strong>LAN</strong> is a network within a single building or campus, owned and managed by that organisation.</p><p><strong>Characteristics:</strong></p><ul><li>Range: single building or campus (up to ~1 km)</li><li>High speed: 100 Mbps to 10 Gbps (Gigabit Ethernet)</li><li>Low latency</li><li>Owned by the organisation</li><li>Technologies: Ethernet (wired), Wi-Fi (wireless)</li></ul><p><strong>Examples:</strong></p><ul><li>School computer lab network</li><li>Office network sharing a printer and file server</li><li>University campus network</li></ul><p><strong>Wired LAN (Ethernet):</strong></p><ul><li>Uses Cat5e, Cat6 cables</li><li>Faster and more secure than Wi-Fi</li><li>Devices connected to a switch</li></ul><p><strong>Wireless LAN (WLAN / Wi-Fi):</strong></p><ul><li>Uses wireless access points (WAPs)</li><li>More flexible — no cables</li><li>Slightly slower, more interference-prone</li></ul><hr><h2 id="man-—-metropolitan-area-network" tabindex="-1">MAN — Metropolitan Area Network <a class="header-anchor" href="#man-—-metropolitan-area-network" aria-label="Permalink to &quot;MAN — Metropolitan Area Network&quot;">​</a></h2><p>A <strong>MAN</strong> covers a city or large town, connecting multiple LANs.</p><p><strong>Characteristics:</strong></p><ul><li>Range: up to 50 km (city-wide)</li><li>Faster than WAN, but more limited than LAN</li><li>Often owned by ISPs, municipalities, or large organisations</li><li>Technologies: fibre optic cable, WiMAX</li></ul><p><strong>Examples:</strong></p><ul><li>City-wide Wi-Fi network provided by municipality</li><li>Network connecting multiple branches of a bank across a city</li><li>ISP infrastructure connecting suburbs to a city exchange</li></ul><hr><h2 id="wan-—-wide-area-network" tabindex="-1">WAN — Wide Area Network <a class="header-anchor" href="#wan-—-wide-area-network" aria-label="Permalink to &quot;WAN — Wide Area Network&quot;">​</a></h2><p>A <strong>WAN</strong> spans large geographic areas — countries or globally. The internet is the world&#39;s largest WAN.</p><p><strong>Characteristics:</strong></p><ul><li>Range: unlimited — can be global</li><li>Slower than LAN (limited by physical distance and infrastructure)</li><li>Usually uses leased lines or public infrastructure</li><li>Technologies: fibre optic cables, satellite, DSL, mobile (4G/5G)</li></ul><p><strong>Examples:</strong></p><ul><li>The internet</li><li>A company&#39;s private network connecting offices in Johannesburg, Cape Town, and London</li><li>ATM banking network</li><li>Video streaming from servers in the USA to South Africa</li></ul><hr><h2 id="lan-vs-wan-comparison" tabindex="-1">LAN vs WAN Comparison <a class="header-anchor" href="#lan-vs-wan-comparison" aria-label="Permalink to &quot;LAN vs WAN Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>LAN</th><th>WAN</th></tr></thead><tbody><tr><td>Geographic range</td><td>Single building/campus</td><td>Countries or global</td></tr><tr><td>Speed</td><td>Very fast (up to 10 Gbps)</td><td>Slower (limited by distance)</td></tr><tr><td>Ownership</td><td>Private (organisation)</td><td>Typically leased or public</td></tr><tr><td>Cost</td><td>Lower</td><td>Higher</td></tr><tr><td>Security</td><td>Easier to secure</td><td>More difficult to secure</td></tr><tr><td>Error rate</td><td>Low</td><td>Higher (longer distance)</td></tr><tr><td>Examples</td><td>School network, office</td><td>Internet, corporate WAN</td></tr></tbody></table><hr><h2 id="client-server-vs-peer-to-peer-networks" tabindex="-1">Client-Server vs Peer-to-Peer Networks <a class="header-anchor" href="#client-server-vs-peer-to-peer-networks" aria-label="Permalink to &quot;Client-Server vs Peer-to-Peer Networks&quot;">​</a></h2><h3 id="client-server" tabindex="-1">Client-Server <a class="header-anchor" href="#client-server" aria-label="Permalink to &quot;Client-Server&quot;">​</a></h3><ul><li><strong>Dedicated server</strong> manages resources, authentication, and storage</li><li>Clients (workstations) request services from the server</li><li>Centralised control → easier management and security</li><li>Used in: businesses, schools, organisations</li></ul><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>Centralised data management</td><td>Expensive server hardware required</td></tr><tr><td>Easier to apply security policies</td><td>Server is single point of failure</td></tr><tr><td>Easy to back up centrally</td><td>Requires IT staff to administer</td></tr><tr><td>Scales well</td><td>Server downtime affects all users</td></tr></tbody></table><h3 id="peer-to-peer-p2p" tabindex="-1">Peer-to-Peer (P2P) <a class="header-anchor" href="#peer-to-peer-p2p" aria-label="Permalink to &quot;Peer-to-Peer (P2P)&quot;">​</a></h3><ul><li>Each device is equal — any can be a client or server</li><li>No central server — devices share directly</li><li>Simpler, cheaper to set up</li><li>Used in: small home networks, file sharing</li></ul><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>No expensive server required</td><td>No central security management</td></tr><tr><td>Easy to set up</td><td>Files scattered across devices</td></tr><tr><td>No single point of failure</td><td>Harder to back up</td></tr><tr><td>Suitable for small networks</td><td>Slows as network grows</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>PAN</strong></td><td>Personal Area Network — connects personal devices within ~10 metres</td></tr><tr><td><strong>HAN</strong></td><td>Home Area Network — devices within a home</td></tr><tr><td><strong>LAN</strong></td><td>Local Area Network — network within a single building or campus</td></tr><tr><td><strong>MAN</strong></td><td>Metropolitan Area Network — city-scale network</td></tr><tr><td><strong>WAN</strong></td><td>Wide Area Network — spans large geographic areas</td></tr><tr><td><strong>Client</strong></td><td>Device that requests services from a server</td></tr><tr><td><strong>Server</strong></td><td>Dedicated device providing services (files, printing, authentication)</td></tr><tr><td><strong>Peer-to-peer</strong></td><td>Network where all devices are equal — no dedicated server</td></tr><tr><td><strong>Ethernet</strong></td><td>Wired LAN technology using twisted-pair cables</td></tr><tr><td><strong>WLAN</strong></td><td>Wireless LAN — uses Wi-Fi (IEEE 802.11 standards)</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between a LAN and a WAN?&quot;</strong> — LAN: single building/campus, high speed, privately owned; WAN: spans large distances/countries, slower, uses leased/public infrastructure</p></li><li><p><strong>&quot;Give ONE example of each: PAN, LAN, WAN&quot;</strong> — PAN: Bluetooth earphones; LAN: school computer lab; WAN: the internet</p></li><li><p><strong>&quot;Give TWO advantages of a client-server network over a P2P network&quot;</strong> — centralised data management; easier to enforce security policies; central backup; scales well</p></li><li><p><strong>&quot;Give TWO disadvantages of a client-server network&quot;</strong> — expensive server hardware; server is single point of failure; requires trained IT staff</p></li><li><p><strong>&quot;What type of network would be most suitable for connecting two branches of a company in different cities? Motivate.&quot;</strong> — WAN; it spans large geographic distances connecting separate locations across cities or countries</p></li></ol></div>',62)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
